package com.welltrack.identity.security; import io.jsonwebtoken.*; import java.util.*; import org.springframework.stereotype.Component; @Component public class JwtUtil{ private final String SECRET="welltrack"; public String gen(String u){return Jwts.builder().setSubject(u).setIssuedAt(new Date()).setExpiration(new Date(System.currentTimeMillis()+86400000)).signWith(SignatureAlgorithm.HS256,SECRET).compact();}}